class Solution {
    public int getMaxRepetitions(String s1, int n1, String s2, int n2) {
        int len1 = s1.length(), len2 = s2.length();
        int count = 0;
        for (int i = 0; i < len1 * n1; i++) {
            if (s1.charAt(i % len1) == s2.charAt(count % len2)) {
                count++;
            }
            if (count == len2) {
                count = 0;
                if (i + 1 >= len1) {
                    return (i + 1) / len1 / n2;
                }
            }
        }
        return 0;
    }
}
```
